;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="If you want to turn back, now is the time!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="If you go any further, you'll see hell!"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="You really should go home now! You never know what's going to happen, it's scary!"

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@question title="<y>Will you drink water from the gushing spring?" cancel=true
[if exp='tf.result']
	@eval exp='o.噴水.doDamage = o.グランドヒール.doDamage'
	@eval exp='o.噴水.resultMessage = o.グランドヒール.resultMessage'
	@btcmd name=噴水
	@notice text="Party's HP restored!"
[endif]

[eventoff]
